# @cctt_verify {"v":2,"sym":"sympy.concrete.tests.test_sums_products.test_hypersum","kind":"function","src_hash":"bf44e0790916cc85","in":{"base":"Any"},"out":{"base":"Any","pred":"simplify(summation(x ** n / fac(n), (n, 1, oo))) == -1 + exp(x) and summation((-1) ** n * x ** (2 * n) / fac(2 * n), (n, 0, oo)) == cos(x) and summation(1 / (n + 2) ** 3, (n, 1, oo)) == Rational(-9, 8) + zeta(3) and summation(1 / n ** 4, (n, 1, oo)) == pi ** 4 / 90 and s.is_Piecewise and s.args[0].args[0] == -1 / (x * (1 - 1 / x) ** 2) and s.args[0].args[1] == (abs(1 / x) < 1) and summation(binomial(m, k), (k, 0, m)) == 2 ** m"},"spec":{"lhs":"test_hypersum()","rhs":"test_hypersum produces the expected output","over":{"base":"Any"},"name":"test_hypersum_correct"},"guarantee":"test_hypersum produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.concrete.tests.test_sums_products.test_hypersum_correct","statement":"Path(test_hypersum(x), test_hypersum produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"b1cfdc9b09cf6878"}
def test_hypersum():
    assert simplify(summation(x**n/fac(n), (n, 1, oo))) == -1 + exp(x)
    assert summation((-1)**n * x**(2*n) / fac(2*n), (n, 0, oo)) == cos(x)
    assert simplify(summation((-1)**n*x**(2*n + 1) /
        factorial(2*n + 1), (n, 3, oo))) == -x + sin(x) + x**3/6 - x**5/120

    assert summation(1/(n + 2)**3, (n, 1, oo)) == Rational(-9, 8) + zeta(3)
    assert summation(1/n**4, (n, 1, oo)) == pi**4/90

    s = summation(x**n*n, (n, -oo, 0))
    assert s.is_Piecewise
    assert s.args[0].args[0] == -1/(x*(1 - 1/x)**2)
    assert s.args[0].args[1] == (abs(1/x) < 1)

    m = Symbol('n', integer=True, positive=True)
    assert summation(binomial(m, k), (k, 0, m)) == 2**m


