# @cctt_verify {"v":2,"sym":"sympy.concrete.tests.test_sums_products.test_change_index","kind":"function","src_hash":"3ea783b50cd787f2","in":{"base":"Any"},"out":{"base":"Any","pred":"Sum(x, (x, a, b)).change_index(x, x + 1, y) == Sum(y - 1, (y, a + 1, b + 1)) and Sum(x ** 2, (x, a, b)).change_index(x, -x, y) == Sum((-y) ** 2, (y, -b, -a)) and Sum(x, (x, a, b)).change_index(x, -x - 1) == Sum(-x - 1, (x, -b - 1, -a - 1)) and Sum(x, (x, a, b)).change_index(x, x + v) == Sum(-v + x, (x, a + v, b + v)) and Sum(x, (x, a, b)).change_index(x, -x - v) == Sum(-v - x, (x, -b - v, -a - v)) and Sum(x, (x, a, b)).change_index(x, w * x, v) == Sum(v / w, (v, b * w, a * w))"},"spec":{"lhs":"test_change_index()","rhs":"test_change_index produces the expected output","over":{"base":"Any"},"name":"test_change_index_correct"},"guarantee":"test_change_index produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.concrete.tests.test_sums_products.test_change_index_correct","statement":"Path(test_change_index(x), test_change_index produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"7ef8852e22b98e48"}
def test_change_index():
    b, v, w = symbols('b, v, w', integer = True)

    assert Sum(x, (x, a, b)).change_index(x, x + 1, y) == \
        Sum(y - 1, (y, a + 1, b + 1))
    assert Sum(x**2, (x, a, b)).change_index( x, x - 1) == \
        Sum((x+1)**2, (x, a - 1, b - 1))
    assert Sum(x**2, (x, a, b)).change_index( x, -x, y) == \
        Sum((-y)**2, (y, -b, -a))
    assert Sum(x, (x, a, b)).change_index( x, -x - 1) == \
        Sum(-x - 1, (x, -b - 1, -a - 1))
    assert Sum(x*y, (x, a, b), (y, c, d)).change_index( x, x - 1, z) == \
        Sum((z + 1)*y, (z, a - 1, b - 1), (y, c, d))
    assert Sum(x, (x, a, b)).change_index( x, x + v) == \
        Sum(-v + x, (x, a + v, b + v))
    assert Sum(x, (x, a, b)).change_index( x, -x - v) == \
        Sum(-v - x, (x, -b - v, -a - v))
    assert Sum(x, (x, a, b)).change_index(x, w*x, v) == \
        Sum(v/w, (v, b*w, a*w))
    raises(ValueError, lambda: Sum(x, (x, a, b)).change_index(x, 2*x))


