# @cctt_verify {"v":2,"sym":"sympy.concrete.tests.test_sums_products.test_issue_14640","kind":"function","src_hash":"d3fee7e70bafadb5","in":{"base":"Any"},"out":{"base":"Any","pred":"not s.has(Sum) and s.subs({a: 2, b: 3, n: 5}) == 122"},"spec":{"lhs":"test_issue_14640()","rhs":"test_issue_14640 produces the expected output","over":{"base":"Any"},"name":"test_issue_14640_correct"},"guarantee":"test_issue_14640 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.concrete.tests.test_sums_products.test_issue_14640_correct","statement":"Path(test_issue_14640(x), test_issue_14640 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f1c57a07d2c32ab0"}
def test_issue_14640():
    i, n = symbols("i n", integer=True)
    a, b, c = symbols("a b c", zero=False)

    assert Sum(a**-i/(a - b), (i, 0, n)).doit() == Sum(
        1/(a*a**i - a**i*b), (i, 0, n)).doit() == Piecewise(
            (n + 1, Eq(1/a, 1)),
            ((-a**(-n - 1) + 1)/(1 - 1/a), True))/(a - b)

    assert Sum((b*a**i - c*a**i)**-2, (i, 0, n)).doit() == Piecewise(
        (n + 1, Eq(a**(-2), 1)),
        ((-a**(-2*n - 2) + 1)/(1 - 1/a**2), True))/(b - c)**2

    s = Sum(i*(a**(n - i) - b**(n - i))/(a - b), (i, 0, n)).doit()
    assert not s.has(Sum)
    assert s.subs({a: 2, b: 3, n: 5}) == 122


